aggregated_labels_db: Dict[str, Dict[str, Any]] = {}

trained_model: Optional[LogisticRegression] = None

# --- Persistence Functions ---
def _load_data(file_path: str, default_data: Any) -> Any:
    if os.path.exists(file_path):
        with open(file_path, 'r') as f:
            return json.load(f)
    return default_data

def _save_data(file_path: str, data: Any):
    with open(file_path, 'w') as f:
        json.dump(data, f, indent=2)

def load_all_data():
    global images_db, annotations_db, aggregated_labels_db, trained_model
    images_db = _load_data(IMAGES_FILE, {})
    annotations_db = _load_data(ANNOTATIONS_FILE, {})
    aggregated_labels_db = _load_data(AGGREGATED_LABELS_FILE, {})
    
    if os.path.exists(TRAINED_MODEL_FILE):
        try:
            with open(TRAINED_MODEL_FILE, 'rb') as f:
                trained_model = pickle.load(f)
        except Exception as e:
            print(f"Warning: Could not load trained model: {e}")
            trained_model = None

def save_all_data():
    _save_data(IMAGES_FILE, images_db)
    _save_data(ANNOTATIONS_FILE, annotations_db)
    _save_data(AGGREGATED_LABELS_FILE, aggregated_labels_db)
    if trained_model:
        with open(TRAINED_MODEL_FILE, 'wb') as f:
            pickle.dump(trained_model, f)

# --- Helper Functions ---
def get_deterministic_features(image_id: str, feature_dim: int = FEATURE_DIM) -> np.ndarray:
    """Generates a deterministic feature vector for an image_id."""
    # Use image_id to seed the random number generator
    seed = int(hashlib.sha256(image_id.encode('utf-8')).hexdigest(), 16) % (2**32 - 1)
    rng = np.random.default_rng(seed)
    return rng.rand(feature_dim)

def _aggregate_labels_for_image(image_id: str) -> Optional[Dict[str, Any]]:
    """Aggregates all labels for a given image_id using majority voting."""
    image_annotations = [
        anno['label'] for anno_id, anno in annotations_db.items() if anno['image_id'] == image_id
    ]

    if not image_annotations:
        return None

    label_counts = Counter(image_annotations)
    most_common = label_counts.most_common(1)

    if not most_common:
        return None

    majority_label, count = most_common[0]
    total_votes = sum(label_counts.values())
    confidence = count / total_votes

    return {
        "majority_label": majority_label,
        "confidence": round(confidence, 2),
        "total_votes": total_votes
    }

def update_aggregated_labels(image_id: str):
    """Updates the aggregated labels for a specific image and persists it."""
    aggregated_data = _aggregate_labels_for_image(image_id)
    if aggregated_data:
        aggregated_labels_db[image_id] = aggregated_data
        _save_data(AGGREGATED_LABELS_FILE, aggregated_labels_db)

